import requests
import json

# Kong Admin API URL
KONG_ADMIN_URL = 'http://your-kong-admin-url:8001'

# Authentication token (if required)
AUTH_TOKEN = 'your-auth-token'

def create_service(service_name, service_url):
    headers = {
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {AUTH_TOKEN}'
    }
    data = {
        "name": service_name,
        "url": service_url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services', headers=headers, data=json.dumps(data))
    if response.status_code == 201:
        print(f"Service '{service_name}' created successfully.")
    else:
        print(f"Failed to create service '{service_name}'. Status code: {response.status_code}")

def create_route(service_id, route_path):
    headers = {
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {AUTH_TOKEN}'
    }
    data = {
        "paths": [route_path],
        "services": [{"id": service_id}]
    }
    response = requests.post(f'{KONG_ADMIN_URL}/routes', headers=headers, data=json.dumps(data))
    if response.status_code == 201:
        print(f"Route for path '{route_path}' created successfully.")
    else:
        print(f"Failed to create route for path '{route_path}'. Status code: {response.status_code}")

def create_upstream(upstream_name):
    headers = {
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {AUTH_TOKEN}'
    }
    data = {
        "name": upstream_name
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', headers=headers, data=json.dumps(data))
    if response.status_code == 201:
        print(f"Upstream '{upstream_name}' created successfully.")
        return response.json()['id']
    else:
        print(f"Failed to create upstream '{upstream_name}'. Status code: {response.status_code}")
        return None

def add_target_to_upstream(upstream_id, target_url):
    headers = {
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {AUTH_TOKEN}'
    }
    data = {
        "target": target_url,
        "weight": 100
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets', headers=headers, data=json.dumps(data))
    if response.status_code == 201:
        print(f"Target '{target_url}' added to upstream successfully.")
    else:
        print(f"Failed to add target '{target_url}' to upstream. Status code: {response.status_code}")

